import { useCallback, useLayoutEffect, useRef, useState, type RefObject } from 'react';
import {
  computePosition,
  createPositionWatcher,
  type Placement,
  type PositionResult,
  type PositionWatcherOptions,
} from '@arvo/core';

export interface UsePositioningOptions {
  anchorRef: RefObject<HTMLElement | null>;
  floatRef: RefObject<HTMLElement | null>;
  placement?: Placement;
  gap?: number;
  enabled?: boolean;
  width?: 'anchor' | number | string;
  observeContainerSelector?: string;
}

export interface UsePositioningReturn {
  position: PositionResult | null;
  update: () => void;
}

export function usePositioning(options: UsePositioningOptions): UsePositioningReturn {
  const {
    anchorRef,
    floatRef,
    placement = 'bottom-start',
    gap = 2,
    enabled = true,
    width,
    observeContainerSelector,
  } = options;

  const [position, setPosition] = useState<PositionResult | null>(null);
  const watcherRef = useRef<ReturnType<typeof createPositionWatcher> | null>(null);

  const optionsRef = useRef<PositionWatcherOptions>({
    placement,
    gap,
    width,
    observeContainerSelector,
  });
  optionsRef.current = { placement, gap, width, observeContainerSelector };

  const update = useCallback(() => {
    if (watcherRef.current) {
      watcherRef.current.update();
    } else if (anchorRef.current && floatRef.current) {
      setPosition(
        computePosition(anchorRef.current, floatRef.current, optionsRef.current),
      );
    }
  }, [anchorRef, floatRef]);

  useLayoutEffect(() => {
    if (!enabled) {
      watcherRef.current?.destroy();
      watcherRef.current = null;
      setPosition(null);
      return;
    }

    const anchor = anchorRef.current;
    const float = floatRef.current;
    if (!anchor || !float) return;

    const watcherOpts: PositionWatcherOptions = {
      placement,
      gap,
      width,
      observeContainerSelector,
    };

    setPosition(computePosition(anchor, float, watcherOpts));

    const watcher = createPositionWatcher(anchor, float, watcherOpts, setPosition);
    watcherRef.current = watcher;

    return () => {
      watcher.destroy();
      watcherRef.current = null;
    };
  }, [anchorRef, floatRef, enabled, placement, gap, width, observeContainerSelector]);

  return { position, update };
}
